# Fungsi menentukan prioritas operator
def prioritas(op):
    if op in ['+', '-']:
        return 1
    elif op in ['*', '/']:
        return 2
    elif op == '^':
        return 3
    return 0


# Fungsi konversi infix ke postfix
def infix_ke_postfix(ekspresi):
    stack = []
    hasil = ""

    for char in ekspresi:
        # operand
        if char.isalnum():
            hasil += char

        # kurung buka
        elif char == '(':
            stack.append(char)

        # kurung tutup
        elif char == ')':
            while stack and stack[-1] != '(':
                hasil += stack.pop()
            stack.pop()

        # operator
        else:
            while stack and prioritas(char) <= prioritas(stack[-1]):
                hasil += stack.pop()
            stack.append(char)

    while stack:
        hasil += stack.pop()

    return hasil


# Fungsi konversi infix ke prefix
def infix_ke_prefix(ekspresi):
    # balik ekspresi
    ekspresi = ekspresi[::-1]

    # tukar kurung
    ekspresi_baru = ""
    for c in ekspresi:
        if c == '(':
            ekspresi_baru += ')'
        elif c == ')':
            ekspresi_baru += '('
        else:
            ekspresi_baru += c

    # ubah ke postfix
    postfix = infix_ke_postfix(ekspresi_baru)

    # balik hasil postfix
    prefix = postfix[::-1]

    return prefix


# Program utama
infix = input("Masukkan ekspresi infix: ")

postfix = infix_ke_postfix(infix)
prefix = infix_ke_prefix(infix)

print("Postfix :", postfix)
print("Prefix  :", prefix)
